var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"여기는……?","JPN":"ここは……？","ENG":"Where am I…?","TWN":"這裡是……？"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"호수는 하나가 되어야만 해……. 하나가 되는 거야…….","JPN":"湖は一つにならないといけない……一つになるのさ……","ENG":"The Lake must be one... Become one...","TWN":"湖水必須合而為一……合而為一……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"우리와 하나가 되자…… 하나가 되자…….","JPN":"私たちと一つになろう……一つになろう……","ENG":"One with us... One with us...","TWN":"和我們合而為一吧……合而為一……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"결국…… 실패한 건가?","JPN":"結局……失敗したのか。","ENG":"So... I failed?","TWN":"最終……還是失敗了嗎？"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"약속을 지키는 것도, 누군가를 구하는 것도…….","JPN":"約束を守ることも、誰かを救うことも……","ENG":"To keep a promise, to save someone...","TWN":"無論是信守諾言，還是救人……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내 손으로는…… 아무것도 이루지 못한 건가……?","JPN":"俺の手では……何も成し遂げられなかったのか……？","ENG":"I couldn't achieve anything... with my own hands...?","TWN":"難道我什麼都……沒能用我的雙手實現嗎……？"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나는…….","JPN":"けど俺は……","ENG":"But I...","TWN":"可我……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"하나가 되자…… 하나가 되자…….","JPN":"一つになろう……一つになろう……","ENG":"Become one... Become one...","TWN":"合而為一吧……合而為一……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"로이 버넷…… 로이 버넷…….","JPN":"ロイ・バーネット……ロイ・バーネット……","ENG":"Roy Burnett... Roy Burnett...","TWN":"羅伊·伯內特……羅伊·伯內特……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 나는 살고 싶어! 살고 싶다고!","JPN":"けど、俺は生きたい！　生きたいんだ！","ENG":"But I want to live! I want to live!","TWN":"但是我想活下去！我想活下去！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제기랄! 겨우 이런 곳에서 비참하게 죽고 싶지는 않아……!","JPN":"くそ！　こんなところで惨めに死にたくない……！","ENG":"Bollocks! I don't want to die miserably in a place like this...!","TWN":"該死！我不想死在這種地方……！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"거기 누구 없어요!","JPN":"誰かいませんか！","ENG":"Is anyone there?!","TWN":"有沒有人啊！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"살려주세요! 살려주세요! 제발……!!","JPN":"助けてください！　助けてください！　頼むから……！！","ENG":"Save me! Save me! Please...!!","TWN":"救命！救命！求求你……！！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제기랄……!! 나 좀 여기서 꺼내달라고……!!","JPN":"ちくしょう……！！　ここから出してくれ……！！","ENG":"Dammit...!! Get me out of here...!!","TWN":"該死……！！把我從這裡弄出去啊……！！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"홍차 폭탄! 집사 할배! 안 들려!? 누구든 좋아! 누구든 좋으니까……!","JPN":"紅茶爆弾！　執事のジジイ！　聞こえてないか！？　誰でもいい、誰でもいいから……！","ENG":"Tea Bomb! Butler! Can anybody hear me?! Anyone will do! Anyone, please...!","TWN":"紅茶炸彈！管家老頭！聽不到嗎？！誰來都行！誰來都行啊……！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 내가 졌어!! 졌다고!!","JPN":"ああ、認める！！　俺の負けだ！！","ENG":"Fine, I lost!! I lost, okay!!","TWN":"好，我輸了！輸了！！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐든지 하라는 대로 할 테니까, 제발……!!","JPN":"なんでも言う通りにするから、頼むから……！！","ENG":"I'll do whatever you tell me to, so, please...!!","TWN":"我什麼都願意做，求求你……！！"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"하나가 되자, 로이 버넷.","JPN":"一つになろう、ロイ・バーネット。","ENG":"Become one with us, Roy Burnett.","TWN":"合而為一吧，羅伊·伯內特。"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"다들 널 기다리고 있어, 널 탐식하길 기대하고 있어.","JPN":"皆あなたを待っている。あなたを貪食したいと期待している。","ENG":"Everyone's waiting for you. They want to devour you.","TWN":"大家都等著你，等著吃掉你。"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"하나가 되자…… 우리의 숙적.","JPN":"一つになろう……我々の宿敵。","ENG":"Become one with us... our nemesis.","TWN":"合而為一吧……我們的宿敵。"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh.*","TWN":"……哈啊。"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"됐어. 이젠 지쳤어. 마음대로 해.","JPN":"もういい、疲れた。勝手にしろ。","ENG":"Whatever. I'm tired now. Do whatever you want.","TWN":"算了，我累了。隨便吧。"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나는 할 만큼 했다고.","JPN":"俺はやれることはやった。","ENG":"I've done enough.","TWN":"我已經盡力了。"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以說……"},"stage":{"bg":"PRYDWEN_02","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};